/* 双陆世界统一人物档案：国家王族、政治人物与组织人物。画像后续再接入。 */
const WORLD_PEOPLE=[];
const PEOPLE_BY_NAME=new Map();
const AGE_LABEL=a=>typeof a==='number'?a+'岁':a;
const Q=s=>String(s||'').replace(/[“”]/g,'');
const hash=s=>[...String(s)].reduce((n,c)=>(n*33+c.charCodeAt(0))>>>0,5381);
function addWorldPerson(p){
  p={gender:'未记录',race:'人类',age:'不详',level:'未公开',status:'在世',house:'—',marriage:'待补充',affiliations:[],traits:[],strengths:[],history:[],relations:[],...p};
  p.id=encodeURIComponent(p.name);p.affiliations=[...new Set(p.affiliations.filter(Boolean))];
  if(!PEOPLE_BY_NAME.has(p.name)){WORLD_PEOPLE.push(p);PEOPLE_BY_NAME.set(p.name,p)}
  else Object.assign(PEOPLE_BY_NAME.get(p.name),p);
  return PEOPLE_BY_NAME.get(p.name);
}
const RELATION_PRIORITY={family:100,feudal:90,office:80,romance:70,mentor:60,social:50,political:40,other:10};
function relationCategory(type){
  if(/父亲|母亲|儿子|女儿|哥哥|姐姐|弟弟|妹妹|丈夫|妻子|未婚夫|未婚妻|亲属/.test(type))return'family';
  if(/情人|面首|恋人|旧情|爱慕/.test(type))return'romance';
  if(/宗主|封臣/.test(type))return'feudal';
  if(/君主|臣子|上司|下属|同僚/.test(type))return'office';
  if(/导师|学生|门生|教官/.test(type))return'mentor';
  if(/朋友|挚友|密友|旧友|战友|知己|同窗|玩伴/.test(type))return'social';
  if(/盟友|对手|竞争|合作|婚约|考察|制衡|对接/.test(type))return'political';
  return'other';
}
function addDirectedRelation(from,to,type,note='',category=relationCategory(type),visibility='公开'){
  const p=PEOPLE_BY_NAME.get(from);if(!p||!PEOPLE_BY_NAME.has(to)||from===to)return;
  const found=p.relations.find(r=>r.name===to);
  if(!found){p.relations.push({name:to,type,note,category,visibility,facets:[]});return}
  if(found.type===type){if(note&&!found.note.includes(note))found.note+=(found.note?' ':'')+note;return}
  const incoming=RELATION_PRIORITY[category]||0,current=RELATION_PRIORITY[found.category]||0;
  const facetLabel=visibility&&visibility!=='公开'?type+'（'+visibility+'）':type;
  if(incoming>current){const oldFacet=found.visibility&&found.visibility!=='公开'?found.type+'（'+found.visibility+'）':found.type;found.facets=[oldFacet,...(found.facets||[])];found.type=type;found.category=category;found.visibility=visibility}
  else if(!(found.facets||[]).includes(facetLabel))found.facets=[...(found.facets||[]),facetLabel];
  if(note&&!found.note.includes(note))found.note+=(found.note?' ':'')+note;
}
function relate(a,b,typeA,note='',typeB=typeA,noteB=note,category='',visibility='公开'){
  addDirectedRelation(a,b,typeA,note,category||relationCategory(typeA),visibility);
  addDirectedRelation(b,a,typeB,noteB,category||relationCategory(typeB),visibility);
}
function numericAge(p){return typeof p.age==='number'?p.age:Number((String(p.age).match(/\d+/)||[NaN])[0])}
function childLabel(child){return child.gender==='男'?'儿子':child.gender==='女'?'女儿':'子女'}
function parentLabel(parent){return parent.gender==='男'?'父亲':parent.gender==='女'?'母亲':'家长'}
function siblingLabel(viewer,target){
  const a=numericAge(viewer),b=numericAge(target),older=Number.isFinite(a)&&Number.isFinite(b)?b>a:null;
  if(target.gender==='男')return older===true?'哥哥':older===false?'弟弟':'兄弟';
  if(target.gender==='女')return older===true?'姐姐':older===false?'妹妹':'姐妹';
  return'手足';
}
function levelBand(level){const n=+(String(level).match(/\d+/)||[0])[0];if(!n)return'未公开';if(n<=20)return'常人阶';if(n<=40)return'精锐阶';if(n<=60)return'英雄阶';if(n<=80)return'传奇阶';if(n<=89)return'半神阶';if(n<=99)return'从神阶';return'主神阶'}
function politicalHistory(p,house){
  const base=p.history?.length?p.history:[];
  if(base.length)return base;
  const first=p.role.includes('皇')||p.role.includes('王')||p.role.includes('公')?'自幼接受宫廷礼法、领地财政与继承政治训练。':'通过家族、军功、考试或宫廷举荐进入国家权力核心。';
  const second=p.focus?'主要经历围绕'+p.focus+'展开，既积累了支持者，也形成了明确的利益对手。':'长期参与宫廷、军务或领地治理，熟悉权力并不等于命令能够自动落实。';
  return[first,second,'当前处在'+house.polity+'的继承、婚姻与派系网络中；其个人选择会受到家族财产、盟约和政治后果约束。'];
}
function addHouse(h){
  const members=[];
  const make=(x,kind)=>{
    const p=addWorldPerson({name:x.name,aliases:x.aliases||[],title:x.role,role:x.role,age:x.age,gender:x.gender,race:x.race||h.race||'人类',level:x.level,house:x.house||h.house,polity:h.polity,affiliations:[h.polity,...(x.affiliations||[])],status:x.status||'在世',succession:x.succession||'—',marriage:x.marriage||'待补充',summary:x.summary||x.focus||h.summary,traits:x.traits||h.traits||[],strengths:x.strengths||[x.focus||'宫廷政治与领地治理',levelBand(x.level)],resources:x.resources||h.resources||'王室身份、封地收入、家臣与政治信用',history:politicalHistory(x,h),relations:[],source:x.source||'扩充设定',kind});members.push(p);return p;
  };
  const ruler=make(h.ruler,'统治者'),consort=h.consort?make(h.consort,'配偶'):null,children=(h.children||[]).map(x=>make(x,'王族后裔')),officials=(h.officials||[]).map(x=>make(x,'国家重臣'));
  if(consort){
    ruler.marriage='已婚；配偶：'+consort.name;consort.marriage='已婚；配偶：'+ruler.name;
    relate(ruler.name,consort.name,consort.gender==='男'?'丈夫':'妻子',h.marriageNote||'这段婚姻同时承担继承、财产与派系平衡功能。',ruler.gender==='男'?'丈夫':'妻子',h.marriageNote||'这段婚姻同时承担继承、财产与派系平衡功能。','family');
  }
  children.forEach(c=>{
    relate(ruler.name,c.name,childLabel(c),c.succession||'王室血亲',parentLabel(ruler),'其继承位置与家族责任会影响亲子关系。','family');
    if(consort)relate(consort.name,c.name,childLabel(c),c.succession||'王室血亲',parentLabel(consort),'其继承位置与家族责任会影响亲子关系。','family');
  });
  for(let i=0;i<children.length;i++)for(let j=i+1;j<children.length;j++)relate(children[i].name,children[j].name,siblingLabel(children[i],children[j]),'既是家人，也是继承顺位、封地和联姻资源上的潜在合作者或竞争者。',siblingLabel(children[j],children[i]),'既是家人，也是继承顺位、封地和联姻资源上的潜在合作者或竞争者。','family');
  officials.forEach(o=>relate(ruler.name,o.name,'臣子','对方以国家职位和专业权力效忠，并非私人仆从。','君主','对方拥有任免与国家决策权，但仍受法律、财政与派系制约。','office'));
  return{...h,members,ruler:ruler.name,consort:consort?.name,children:children.map(x=>x.name),officials:officials.map(x=>x.name)};
}

const POLITICAL_HOUSES=[];
const H=h=>{const x=addHouse(h);POLITICAL_HOUSES.push(x);return x};

