/* 公国人物采用较紧凑档案：统治者、配偶与两名主要后裔；附属公国另接宗主君主。 */
function DH(polity,house,ruler,consort,children,overlord='',extra={}){
  const x=H({polity,house,summary:extra.summary||polity+'的统治家族；继承、封地债务和宗主关系共同限制其选择。',ruler,consort,children,officials:extra.officials||[],traits:extra.traits||['领地利益','家族延续','地方派系'],resources:extra.resources||'公爵领、家臣、地方税权与婚姻盟友'});
  if(overlord){x.overlord=overlord;relate(x.ruler,overlord,'宗主','公国保留内部治理权，但军役、外交和继承确认受到宗主国约束。','封臣','对方保留内部治理权，同时承担军役、外交服从与继承确认义务。','feudal')};return x;
}
