function inversePrivateRelation(type){if(/旧情/.test(type))return'旧情人';if(/秘密情/.test(type))return'秘密情人';if(/情人|伴侣/.test(type))return'情人';return'庇护者'}
PRIVATE_COURTS.forEach(c=>{
 const made=c.entries.map((e,i)=>{const [name,title,age,gender,level,relation,visibility,origin]=e,marriage=i%4===3?'已婚；与原配长期分居，法律婚姻仍然有效':'未婚；依附于'+c.court+'的私人伴侣制度',race=c.polity==='永翠精灵王庭'?'精灵':c.polity==='银脉王国'?'矮人':'人类',p=addWorldPerson({name,title,role:title,age,gender,race,level,house:origin.split('，')[0],polity:c.polity,patron:c.patron,court:c.court,legalStanding:c.standing,affiliations:[c.polity],status:'在世',succession:'无合法继承权',marriage,summary:origin+'。其地位依赖君主私人信任，而非正式国家官职。',traits:[i===0?'内廷核心':'依附王恩',i%3===0?'谨慎经营':'派系敏感'],strengths:[title,levelBand(level),'宫廷生存'],resources:i===0?'私室预算、觐见次序、侍从人事与君主私人信任':'私人俸给、君主通行许可、原生家族与同侪消息',history:[origin+'。',`进入${c.court}后以“${relation}”身份获得俸给与居所；这不等于拥有国家官职或继承权。`,`当前必须在君主宠信、合法配偶的边界、同侪竞争和原生家族索求之间维持平衡。`],relations:[],source:'私人宫廷扩充设定',kind:'宫廷私属'});relate(c.patron,name,relation,`${c.standing} ${origin}。`,inversePrivateRelation(relation),`其生活、俸给和家族前途与${c.patron}的私人信任绑定。`,'romance',visibility);return p});
 for(let i=0;i<made.length-1;i++)relate(made[i].name,made[i+1].name,i%2?'私室盟友':'竞争对手','双方争夺陪伴时段、预算、礼物、家族请托和对君主情绪的解释权。',i%2?'私室盟友':'竞争对手','双方争夺陪伴时段、预算、礼物、家族请托和对君主情绪的解释权。','political','内廷知情');
 const house=POLITICAL_HOUSES.find(h=>h.ruler===c.patron);if(house?.consort&&made[0])relate(house.consort,made[0].name,'监视对象','合法配偶允许私人伴侣制度存在，但会严密监控地产、子女、礼物和政治请托。','合法配偶','对方掌握婚姻法统、继承程序与内廷惩戒权。','political');
});

function setUnion(aName,bName,state,note){
  const a=worldPerson(aName),b=worldPerson(bName);if(!a||!b)return;
  if(state==='已婚'){
    a.marriage='已婚；配偶：'+b.name;b.marriage='已婚；配偶：'+a.name;
    relate(a.name,b.name,b.gender==='男'?'丈夫':'妻子',note,a.gender==='男'?'丈夫':'妻子',note,'family');
  }else{
    a.marriage='订婚；'+(b.gender==='男'?'未婚夫：':'未婚妻：')+b.name;b.marriage='订婚；'+(a.gender==='男'?'未婚夫：':'未婚妻：')+a.name;
    relate(a.name,b.name,b.gender==='男'?'未婚夫':'未婚妻',note,a.gender==='男'?'未婚夫':'未婚妻',note,'family');
  }
}

