/* 给未被重点手写的人物补一层日常社会关系，避免人人只有血缘和职位。 */
function socialKey(p){const h=POLITICAL_HOUSES.find(x=>x.polity===p.polity);if(h?.overlord)return h.overlord;if(h&&POLITICAL_HOUSES.some(x=>x.overlord===h.ruler))return h.ruler;return p.race+':'+(p.kind==='组织人物'?'组织圈':p.kind==='国家重臣'?'官僚圈':'独立宫廷')}
function connectSocialPool(pool,label,note){
  const covered=new Set(pool.filter(p=>p.relations.some(r=>r.category==='social')).map(p=>p.name));
  pool.forEach(p=>{if(covered.has(p.name))return;const age=numericAge(p),valid=q=>q!==p&&q.house!==p.house&&!p.relations.some(r=>r.name===q.name);let candidates=pool.filter(q=>valid(q)&&!covered.has(q.name));if(!candidates.length)candidates=pool.filter(valid);if(!candidates.length)return;const q=candidates.sort((a,b)=>{const ka=(socialKey(a)===socialKey(p)?0:120)+(a.race===p.race?0:35)+Math.abs((numericAge(a)||age||30)-(age||30));const kb=(socialKey(b)===socialKey(p)?0:120)+(b.race===p.race?0:35)+Math.abs((numericAge(b)||age||30)-(age||30));return ka-kb||a.name.localeCompare(b.name,'zh-CN')})[0];relate(p.name,q.name,label,note,label,note,'social');covered.add(p.name);covered.add(q.name)})
}
connectSocialPool(WORLD_PEOPLE.filter(p=>p.kind==='王族后裔'&&Number.isFinite(numericAge(p))&&numericAge(p)<18),'童年玩伴','双方在宫廷教育、节庆或作为人质式访学期间结识，关系尚未完全被政治利益取代。');
connectSocialPool(WORLD_PEOPLE.filter(p=>p.kind==='王族后裔'&&numericAge(p)>=18),'朋友','双方通过学院、宫廷访问或共同差事建立私交；这段关系并不自动等于两国结盟。');
connectSocialPool(WORLD_PEOPLE.filter(p=>p.kind==='统治者'),'旧友','双方在继位前的访问、战争或谈判中建立私人信任，但国家利益仍可能使他们站到对立面。');
connectSocialPool(WORLD_PEOPLE.filter(p=>p.kind==='国家重臣'),'旧同僚','双方在军务、学院或外交差事中长期相识，能绕过正式公文先行交换消息。');
connectSocialPool(WORLD_PEOPLE.filter(p=>p.kind==='组织人物'),'同行朋友','双方在跨组织任务或专业会议中结识，私交能够促成沟通，却不能替代正式授权。');

function adultAge(p){if(p.race==='精灵')return 50;if(p.race==='半精灵')return 30;if(/矮人/.test(p.race))return 40;if(p.race==='古龙')return 300;return 18}
function finalizeMarriage(p){
  if(p.marriage&&p.marriage!=='—'&&p.marriage!=='待补充')return;
  const age=numericAge(p);if(Number.isFinite(age)&&age<adultAge(p)){p.marriage='未婚；尚未达到本族正式婚龄';return}
  const n=hash(p.name)%10;
  if(p.kind==='组织人物'&&(/不公开|匿名|身份保密/.test(p.gender+p.house+p.title))){p.marriage='未公开；组织档案不记录其私人婚姻';return}
  if(p.kind==='王族后裔'){p.marriage='未婚；暂无公开婚约';return}
  if(n<5)p.marriage='已婚；配偶未列入核心人物档案';
  else if(n<7)p.marriage='丧偶；目前未再婚';
  else if(n===7)p.marriage='离婚或分居；档案未记录现任伴侣';
  else p.marriage='未婚；暂无公开伴侣';
}
WORLD_PEOPLE.forEach(finalizeMarriage);
