function worldPerson(name){return PEOPLE_BY_NAME.get(Q(decodeURIComponent(name||'')))}
function peopleForAffiliation(name){return WORLD_PEOPLE.filter(p=>p.affiliations.includes(name)||p.polity===name||p.organization===name)}
